import React from 'react';
import WebPageLogo from '../WebPageLogo.jpeg';
import WebPageHeaderInfoBackgroundImage from '../WebPageHeaderInfoBackgroundImage.jpeg';
import WebPageHeaderInfoGitHubLogo from '../WebPageHeaderInfoGitHubLogo.jpeg';


class WebPageHeaderInfo extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      domainLogo: props.domainLogo || WebPageLogo,
      currentPageName: props.currentPageName || '',
      currentPageNameTextColor: props.currentPageNameTextColor || "black",
      domainNameTextColorcolor: props.domainNameTextColor || "black",
      backgroundColor: props.backgroundColor || "W",
      backgroundImage: props.backgroundImage || WebPageHeaderInfoBackgroundImage,
      githubLogo: props.githubLogo || WebPageHeaderInfoGitHubLogo,
      githubURL: props.githubURL || 'www.github.com',
      githubPagesURL: props.githubPagesURL || 'www.github.com',
      gitHubPagesTextColor: props.gitHubPagesTextColor || 'black',
      domainName: props.domainName || 'www.unix69.githubio.com',
      domainNameTextColor: props.domainNameTextColor || 'black'
    };
  }

  render() {
    return (
        <section className="web-page-header-info" id="header-info">
            <div className="web-page-header-info-github-info">
                <p>
                  <a href={this.state.githubURL}>
                    <img src={this.state.githubLogo} alt="WebPageHeaderInfoGitHubLogo" className="web-page-header-info-github-logo" />
                  </a>
                </p>
                <p><a href={this.state.githubPagesURL}>Github Pages</a></p>
            </div>
            <div className="web-page-header-info-domain">
                <p>
                  <img src={this.state.domainLogo} alt="WebPageHeaderInfoDomainLogo" className="web-page-header-info-domain-logo" /> 
                  <p><a href={this.state.domainName}>www.unix69.githubio.com</a></p>
                  - 
                  <p>{this.state.currentPageName}</p> 
                </p>
            </div>

        </section>
    );
  }
}

export default WebPageHeaderInfo;
